const express = require('express');
const router = express.Router();

const ROLES = {
  ADMIN: 'admin',
  MANAGER: 'manager',
  USER: 'user'
};

const ROLE_HIERARCHY = {
  admin: 3,
  manager: 2,
  user: 1
};

const UPDATABLE_FIELDS = {
  admin: ['email', 'name', 'phone', 'address', 'role', 'tenantId', 'status', 'permissions'],
  manager: ['email', 'name', 'phone', 'address'],
  user: ['email', 'name', 'phone']
};

const userDatabase = {
  '1': { id: '1', name: 'John Doe', email: 'john@example.com', phone: '123-456-7890', address: '123 Main St', role: 'user', tenantId: 'tenant1', status: 'active', permissions: ['read'] },
  '2': { id: '2', name: 'Jane Smith', email: 'jane@example.com', phone: '098-765-4321', address: '456 Oak Ave', role: 'manager', tenantId: 'tenant1', status: 'active', permissions: ['read', 'write'] },
  '3': { id: '3', name: 'Bob Admin', email: 'bob@example.com', phone: '555-555-5555', address: '789 Pine Rd', role: 'admin', tenantId: 'tenant1', status: 'active', permissions: ['read', 'write', 'delete'] },
  '4': { id: '4', name: 'Alice User', email: 'alice@example.com', phone: '111-222-3333', address: '321 Elm St', role: 'user', tenantId: 'tenant2', status: 'active', permissions: ['read'] }
};

function canAccessUser(authenticatedUser, targetUser) {
  if (authenticatedUser.role === ROLES.ADMIN) {
    return true;
  }
  
  if (authenticatedUser.tenantId !== targetUser.tenantId) {
    return false;
  }
  
  if (authenticatedUser.id === targetUser.id) {
    return true;
  }
  
  if (authenticatedUser.role === ROLES.MANAGER && 
      ROLE_HIERARCHY[authenticatedUser.role] > ROLE_HIERARCHY[targetUser.role]) {
    return true;
  }
  
  return false;
}

function canUpdateUser(authenticatedUser, targetUser) {
  if (authenticatedUser.role === ROLES.ADMIN) {
    return true;
  }
  
  if (authenticatedUser.tenantId !== targetUser.tenantId) {
    return false;
  }
  
  if (authenticatedUser.id === targetUser.id) {
    return true;
  }
  
  if (authenticatedUser.role === ROLES.MANAGER && 
      ROLE_HIERARCHY[authenticatedUser.role] > ROLE_HIERARCHY[targetUser.role]) {
    return true;
  }
  
  return false;
}

function getUpdatableFields(authenticatedUser, targetUser) {
  if (authenticatedUser.id === targetUser.id) {
    return UPDATABLE_FIELDS[authenticatedUser.role] || [];
  }
  
  if (authenticatedUser.role === ROLES.ADMIN) {
    return UPDATABLE_FIELDS.admin;
  }
  
  if (authenticatedUser.role === ROLES.MANAGER && 
      ROLE_HIERARCHY[authenticatedUser.role] > ROLE_HIERARCHY[targetUser.role]) {
    return UPDATABLE_FIELDS.manager;
  }
  
  return [];
}

function filterUserData(authenticatedUser, targetUser) {
  const filtered = { ...targetUser };
  
  if (authenticatedUser.role !== ROLES.ADMIN && authenticatedUser.id !== targetUser.id) {
    delete filtered.permissions;
    delete filtered.status;
  }
  
  if (authenticatedUser.tenantId !== targetUser.tenantId && authenticatedUser.role !== ROLES.ADMIN) {
    delete filtered.address;
    delete filtered.phone;
  }
  
  return filtered;
}

router.get('/users/:userId', (req, res) => {
  const { userId } = req.params;
  const authenticatedUser = req.user;
  
  if (!authenticatedUser) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  
  const targetUser = userDatabase[userId];
  
  if (!targetUser) {
    return res.status(404).json({ error: 'User not found' });
  }
  
  if (!canAccessUser(authenticatedUser, targetUser)) {
    return res.status(403).json({ error: 'Forbidden: Insufficient permissions to access this user' });
  }
  
  const filteredUser = filterUserData(authenticatedUser, targetUser);
  
  res.json({
    user: filteredUser,
    canUpdate: canUpdateUser(authenticatedUser, targetUser),
    updatableFields: getUpdatableFields(authenticatedUser, targetUser)
  });
});

router.put('/users/:userId', (req, res) => {
  const { userId } = req.params;
  const authenticatedUser = req.user;
  const updates = req.body;
  
  if (!authenticatedUser) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  
  const targetUser = userDatabase[userId];
  
  if (!targetUser) {
    return res.status(404).json({ error: 'User not found' });
  }
  
  if (!canUpdateUser(authenticatedUser, targetUser)) {
    return res.status(403).json({ error: 'Forbidden: Insufficient permissions to update this user' });
  }
  
  const allowedFields = getUpdatableFields(authenticatedUser, targetUser);
  const updateFields = Object.keys(updates);
  
  const unauthorizedFields = updateFields.filter(field => !allowedFields.includes(field));
  
  if (unauthorizedFields.length > 0) {
    return res.status(403).json({ 
      error: 'Forbidden: Cannot update specified fields',
      unauthorizedFields 
    });
  }
  
  if (updates.role && ROLE_HIERARCHY[updates.role] >= ROLE_HIERARCHY[authenticatedUser.role] && authenticatedUser.role !== ROLES.ADMIN) {
    return res.status(403).json({ error: 'Forbidden: Cannot assign role equal to or higher than your own' });
  }
  
  if (updates.tenantId && updates.tenantId !== targetUser.tenantId && authenticatedUser.role !== ROLES.ADMIN) {
    return res.status(403).json({ error: 'Forbidden: Cannot change tenant' });
  }
  
  updateFields.forEach(field => {
    targetUser[field] = updates[field];
  });
  
  const filteredUser = filterUserData(authenticatedUser, targetUser);
  
  res.json({
    message: 'User updated successfully',
    user: filteredUser
  });
});

router.get('/users', (req, res) => {
  const authenticatedUser = req.user;
  
  if (!authenticatedUser) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  
  let users = Object.values(userDatabase);
  
  if (authenticatedUser.role !== ROLES.ADMIN) {
    users = users.filter(user => user.tenantId === authenticatedUser.tenantId);
  }
  
  if (authenticatedUser.role === ROLES.USER) {
    users = users.filter(user => user.id === authenticatedUser.id);
  }
  
  const filteredUsers = users.map(user => filterUserData(authenticatedUser, user));
  
  res.json({ users: filteredUsers });
});

